module top_module(
input             clk,
input             rst_n,
input   [31:0]    pc_in,
output  [31:0]    pc_out
);reg   [31:0]   invalid_pc;

always @(posedge clk or negedge rst_n)
begin
    if(!rst_n)
        invalid_pc <= 32'b0;
    else
        invalid_pc <= pc_in;
end

assign pc_out = invalid_pc;

endmodule
